#include <stdio.h>

int main()
{
	long long init[14], copy[14];
	long long MAX = 0;

	int i;
	for (i = 0; i < 14; i++) {
		scanf("%lli", &init[i]);
	}
	for (i = 0; i < 14; i++) {
		if (init[i] != 0) {
			int j;
			long long score = 0;

			for (j = 0; j < 14; j++) {
				copy[j] = init[j];
			}
            copy[i] = 0;
			for (j = 0; j < 14; j++) {
				copy[j] += init[i]/14;
			}
            int extr = init[i]%14;
            for (j = 1; j <= extr; j++) {
                copy[(i+j)%14]++;
            }
			for(j = 0; j < 14; j++){
				if (copy[j]%2 == 0) score += copy[j];
			}
			if (MAX < score) MAX = score;
		}
	}
	printf("%lli", MAX);
	return 0;
}

