fn main() {
    let mut stdin = String::new();
    std::io::Read::read_to_string(
        &mut std::io::stdin(),
        &mut stdin).unwrap();
    let mut stdin = stdin.split_whitespace();
    let mut get = || stdin.next().unwrap();
    macro_rules! get {
        () => (get!(i64));
        ($t:ty) => (get().parse::<$t>().unwrap());
    }

    let n = 14;
    let mut xs = vec![];
    for _ in 0..n {
        let x = get!();
        xs.push(x);
    }
    let mut ans = 0;
    for i in 0..n {
        let x = xs[i];
        let d = x / 14;
        let r = (x % 14) as usize;
        xs[i] = 0;
        let mut tmp = 0;
        for j in 0..n {
            let mut e = xs[j] + d;
            if i < j && j <= i + r {
                e += 1;
            } else if i < j + 14 && j + 14 <= i + r {
                e += 1;
            }
            if e % 2 == 0 {
                tmp += e;
            }
        }
        ans = std::cmp::max(ans, tmp);
        xs[i] = x;
    }
    println!("{}", ans);
}
